mapper.select:

WHERE p.status = 'PUBLIC' AND p.deleted_at IS NULL

    AND c.slug = #{p.categorySlug}


    AND p.id IN (
        SELECT pt2.post_id FROM post_tags pt2 JOIN tags t2 ON t2.id = pt2.tag_id WHERE t2.name = #{p.tagName}
    )

GROUP BY p.id, c.name, c.slug

    ORDER BY p.view_count DESC, p.id DESC
    ORDER BY p.like_count DESC, p.id DESC
    ORDER BY p.created_at DESC, p.id DESC

LIMIT #{p.limit} OFFSET #{p.offset}

SELECT COUNT(DISTINCT p.id)
FROM posts p
LEFT JOIN categories c ON c.id = p.category_id
WHERE p.status = 'PUBLIC' AND p.deleted_at IS NULL

    AND c.slug = #{p.categorySlug}


    AND p.id IN (
        SELECT pt2.post_id FROM post_tags pt2 JOIN tags t2 ON t2.id = pt2.tag_id WHERE t2.name = #{p.tagName}
    )


WHERE p.deleted_at IS NULL

    AND p.status = #{p.status}


    AND p.category_id = #{p.categoryId}


    AND p.id IN (
        SELECT pt2.post_id FROM post_tags pt2 JOIN tags t2 ON t2.id = pt2.tag_id WHERE t2.name = #{p.tagName}
    )


    AND p.created_at >= #{p.dateFrom}


    AND p.created_at < DATE_ADD(#{p.dateTo}, INTERVAL 1 DAY)

GROUP BY p.id, c.name, c.slug
ORDER BY p.created_at DESC, p.id DESC
LIMIT #{p.limit} OFFSET #{p.offset}

SELECT COUNT(DISTINCT p.id)
FROM posts p
WHERE p.deleted_at IS NULL

    AND p.status = #{p.status}


    AND p.category_id = #{p.categoryId}


    AND p.id IN (
        SELECT pt2.post_id FROM post_tags pt2 JOIN tags t2 ON t2.id = pt2.tag_id WHERE t2.name = #{p.tagName}
    )


    AND p.created_at >= #{p.dateFrom}


    AND p.created_at < DATE_ADD(#{p.dateTo}, INTERVAL 1 DAY)

SELECT id, title, slug FROM posts
WHERE status = 'PUBLIC' AND deleted_at IS NULL
  AND id != #{postId}
  AND created_at < #{createdAt}
ORDER BY created_at DESC
LIMIT 1

SELECT id, title, slug FROM posts
WHERE status = 'PUBLIC' AND deleted_at IS NULL
  AND id != #{postId}
  AND created_at > #{createdAt}
ORDER BY created_at ASC
LIMIT 1
